module jpeg_compression (
    input [7:0] pixel_in,
    output reg [3:0] obf_compressed_out
);

always @(*) begin
    if (pixel_in < 64)
        obf_compressed_out = 0;
    else if (pixel_in < 128)
        obf_compressed_out = 1;
    else if (pixel_in < 192)
        obf_compressed_out = 2;
    else
        obf_compressed_out = 3;
end

endmodule
